import{c as l,a,q as n,b as p,p as e,e as t,i}from"./index-CUwneGr6.js";const d="/Rincatia-Planet/assets/primary-poster-BDV7AKMY.png",o="/Rincatia-Planet/assets/primary-title-D--bSxiq.png",v="/Rincatia-Planet/assets/primary-TianMiaoke-pn72-2DL.png",h="/Rincatia-Planet/assets/primary-LinZiyao-DqP9uGB4.png",g="/Rincatia-Planet/assets/primary-ZhouDundun-BbmJR-E7.png",m="/Rincatia-Planet/assets/primary-MurongYunxue-BIvwVYzY.png",y="/Rincatia-Planet/assets/primary-Ruxiannaer-Dm_p3g2u.png",b="/Rincatia-Planet/assets/primary-school-aerial-Bcsj-a8B.png",u="/Rincatia-Planet/assets/primary-school-sign-OQ5uEvt5.jpg",f="/Rincatia-Planet/assets/primary-life1-DTnbnOjh.png",F="/Rincatia-Planet/assets/primary-life2-DNI9BwJx.png",k={class:"sub-page"},w={class:"sub-nav-tabs"},_={key:0,class:"spinoff-section"},q={key:1},P={key:2},C={__name:"DerivativeWorks",setup(B){const c=t("miaoke");return(R,s)=>(i(),l("div",k,[s[6]||(s[6]=a("div",{class:"page-header"},[a("h2",{class:"sub-page-title"},"衍生作品"),a("p",{class:"sub-page-desc"},"《光线传奇》系列的衍生作品，展现更丰富的故事世界")],-1)),a("div",w,[a("button",{class:n(["sub-nav-tab",{active:c.value==="miaoke"}]),onClick:s[0]||(s[0]=r=>c.value="miaoke")},"《妙可的小学生活》",2),a("button",{class:n(["sub-nav-tab",{active:c.value==="night"}]),onClick:s[1]||(s[1]=r=>c.value="night")},"《倾听夜的风雨》",2),a("button",{class:n(["sub-nav-tab",{active:c.value==="ice"}]),onClick:s[2]||(s[2]=r=>c.value="ice")},"《冰雪圆舞曲》",2)]),c.value==="miaoke"?(i(),l("section",_,[...s[3]||(s[3]=[p('<div class="section-card spinoff-hero-card"><div class="spinoff-hero-inner"><div class="spinoff-poster-col"><img src="'+d+'" alt="妙可的小学生活剧照" class="spinoff-poster-img"></div><div class="spinoff-hero-text"><img src="'+o+'" alt="妙可的小学生活" class="spinoff-title-logo"><div class="spinoff-badges"><span class="spinoff-badge">📖 日常向</span><span class="spinoff-badge">🌸 治愈向</span><span class="spinoff-badge">✨ 光线传奇衍生</span></div><p class="spinoff-meta">青竹区第一小学 · 五年级(2)班 · 2026年</p><p class="spinoff-tagline">如果没有那道光箭——她的童年，会是什么样？</p><p class="spinoff-director">导演：田野  ·  华田中央大学艺术传媒学院</p></div></div></div><div class="setting-cards-row"><div class="setting-mini-card"><span class="setting-emoji">🏫</span><span class="setting-label">华田市青竹区</span><span class="setting-val">第一小学</span></div><div class="setting-mini-card"><span class="setting-emoji">🎒</span><span class="setting-label">五年级 (2) 班</span><span class="setting-val">最普通的班级</span></div><div class="setting-mini-card"><span class="setting-emoji">📅</span><span class="setting-label">2026 年</span><span class="setting-val">日记式叙事</span></div><div class="setting-mini-card"><span class="setting-emoji">👁️</span><span class="setting-label">核心命题</span><span class="setting-val">被看见的瞬间</span></div></div><div class="section-card"><h3>📚 关于这个故事</h3><div class="story-overview"><p>《妙可的小学生活》（The Milky Chronicles: Primary）是《光线传奇》（Light Legend）系列中的主角<strong>田妙可</strong>的衍生番外篇。遵循「弱关联、强独立」原则——这里只有华田市青竹区第一小学五（2）班的日常，没有星光，没有宿命，只有课间的零食、放学的小路、排练的闹剧，和一群不会离开的人。</p><p>假如，妙可起初就是普通的地球小学女生，她将如何度过自己的小学生活呢。故事以华田市青竹区第一小学为舞台，围绕五年二班一群活蹦乱跳的小学生展开。</p><p>二班班长<strong style="color:cyan;">田妙可</strong>，表面上是老师最放心的小助手，内心却藏着一个疯狂吐槽的灵魂——同桌<strong style="color:cyan;">林梓耀</strong>每次装酷必翻车，前桌<strong style="color:cyan;">周敦敦</strong>的书包永远塞满零食，后排的<strong style="color:cyan;">慕容云雪</strong>一周说的话不超过三句但每句都直击要害。班主任<strong style="color:cyan;">茹仙娜尔·哈米提</strong>老师温柔起来像妈妈，专治各种不服时连校长都绕着走；体育老师<strong style="color:cyan;">夏雨</strong>最怕下雨天，因为一下雨他就得在教室里给孩子们上理论课，而底下会伸起十几只抢答抢到打起来的小手。还有爱哭的李小萌、爱接话茬的赵一鸣、永远穿错对方校服的双胞胎钱朵朵和钱果果、能把任何课文读成猴子上树声调的孙大圣，以及安静坐在角落画画的周小雅，还有后来的既爱说大道理又爱搞小发明但只有偶尔能成功的转学生<strong style="color:cyan;">翟博</strong>——十一张课桌，十一种性格，每一天都在制造着不大不小的热闹。 故事以单元剧形式展开：第一次戴红领巾时林梓耀把红领巾系成了死疙瘩，妙可一边帮他解一边在心里翻了八个白眼；周敦敦报名了兴趣班竞赛中所有带“吃”字的项目，结果在吃包子的比赛中以绝对优势夺冠；教师节全班偷偷排练节目，慕容云雪负责写诗，四句话让茹仙娜尔老师哭掉了半盒纸巾。还有那些只有孩子才懂的烦恼——林梓耀觉得自己已经够酷了为什么妙可就是不看他，周敦敦认真思考过如果零食吃完了世界会不会毁灭，妙可在放学路上对着银河发呆，总觉得那条“牛奶之路”的尽头，好像有什么在等她。</p><p>它回答了正传三部曲都未曾触及的问题：如果没有光箭与使命，妙可依然会是妙可。她的善良、倔强与温柔，从来不是命运赋予的，而是她与生俱来的底色。只是这一次，她不必独自承担两个星球的重量——她只需要在七月某个炎热的下午，和十个伙伴一起，把暑假作业堆成纸飞机，看着它们划过夏季的天空，飞向那条若隐若现的银河。</p><blockquote class="story-quote">「普通班的普通孩子，过着普通的日子，但每一件小事都被认真对待。」</blockquote></div></div><div class="section-card"><h3>🃏 班级成员档案</h3><div class="char-grid"><div class="char-card"><div class="char-photo-wrap"><img src="'+v+'" alt="田妙可" class="char-photo"></div><div class="char-body"><span class="char-role-tag" style="background:#FF85A1;">班长 · 主角</span><h4 class="char-name">田妙可 <span class="char-age">9岁</span></h4><p class="char-desc">表面靠谱班长，内心疯狂吐槽役。嘴硬心软，扎高马尾，生气会叉腰。</p><div class="char-quote">「我上辈子是造了什么孽」</div><div class="char-tags"><span class="char-tag">圆心</span><span class="char-tag">护短</span><span class="char-tag">有原则</span></div></div></div><div class="char-card"><div class="char-photo-wrap"><img src="'+h+'" alt="林梓耀" class="char-photo"></div><div class="char-body"><span class="char-role-tag" style="background:#FF9F43;">体育委员</span><h4 class="char-name">林梓耀 <span class="char-age">10岁</span></h4><p class="char-desc">爱装酷必翻车，懂所有热梗，装酷3秒必社死。校服领口永远敞着。</p><div class="char-quote">「家人们谁懂啊」</div><div class="char-tags"><span class="char-tag">显眼包</span><span class="char-tag">热梗</span><span class="char-tag">关键靠谱</span></div></div></div><div class="char-card"><div class="char-photo-wrap"><img src="'+g+'" alt="周敦敦" class="char-photo"></div><div class="char-body"><span class="char-role-tag" style="background:#FFC530;color:#333;">开心果</span><h4 class="char-name">周敦敦 <span class="char-age">9岁</span></h4><p class="char-desc">吃货梗王，人间清醒。书包永远有吃的，兜里能掏出任何零食。</p><div class="char-quote">「春游主打一个碳水爆炸」</div><div class="char-tags"><span class="char-tag">吃货</span><span class="char-tag">暖</span><span class="char-tag">清醒</span></div></div></div><div class="char-card"><div class="char-photo-wrap"><img src="'+m+'" alt="慕容云雪" class="char-photo"></div><div class="char-body"><span class="char-role-tag" style="background:#74B9FF;">温柔闺蜜</span><h4 class="char-name">慕容云雪 <span class="char-age">10岁</span></h4><p class="char-desc">文静毒舌，一击必杀。话极少，却一开口就是精准吐槽。手里捏着星星纸。</p><div class="char-quote">「你们俩的刀盾，就是一包薯片和半瓶可乐」</div><div class="char-tags"><span class="char-tag">静</span><span class="char-tag">毒舌</span><span class="char-tag">洞察</span></div></div></div><div class="char-card"><div class="char-photo-wrap"><img src="'+y+'" alt="茹仙娜尔" class="char-photo"></div><div class="char-body"><span class="char-role-tag" style="background:#00B894;">班主任</span><h4 class="char-name">茹仙娜尔·哈米提 <span class="char-age">26岁</span></h4><p class="char-desc">温柔但专治各种不服。带新疆口音，能精准拿捏所有学生和夏雨老师。</p><div class="char-quote">「敦敦，你书包里的自热火锅，是给我当春游礼的？」</div><div class="char-tags"><span class="char-tag">托</span><span class="char-tag">安全感</span><span class="char-tag">顶端</span></div></div></div><div class="char-card"><div class="char-photo-wrap char-emoji-avatar"><span class="char-emoji">🚴</span></div><div class="char-body"><span class="char-role-tag" style="background:#55EFC4;color:#333;">体育老师</span><h4 class="char-name">夏雨 <span class="char-age">30岁</span></h4><p class="char-desc">骑破自行车叮当响，爱摸鱼，跟学生互怼，玩梗比学生还溜，就怕茹老师。</p><div class="char-quote">「要是下雨，我当场把这自行车吃了」</div><div class="char-tags"><span class="char-tag">乐</span><span class="char-tag">损友</span><span class="char-tag">怕茹老师</span></div></div></div><div class="char-card"><div class="char-photo-wrap char-emoji-avatar"><span class="char-emoji">🔬</span></div><div class="char-body"><span class="char-role-tag" style="background:#A29BFE;">转校生</span><h4 class="char-name">翟博 <span class="char-age">10岁</span></h4><p class="char-desc">内向腼腆，戴细框圆眼镜。理论满级，小发明家，发明经常翻车。待压轴登场。</p><div class="char-quote">「台词创作中...」</div><div class="char-tags"><span class="char-tag">理</span><span class="char-tag">发明</span><span class="char-tag">待登场</span></div></div></div></div></div><div class="section-card"><h3>🕸️ 班级化学反应</h3><div class="relations-grid"><div class="relation-card"><div class="rel-pair"><span class="rel-name" style="color:#FF85A1;">妙可</span><span class="rel-arrow">↔</span><span class="rel-name" style="color:#FF9F43;">梓耀</span></div><div class="rel-label">「管与被管」</div><p class="rel-desc">妙可管梓耀，梓耀怕妙可，但关键时刻互相撑腰</p></div><div class="relation-card"><div class="rel-pair"><span class="rel-name" style="color:#FF85A1;">妙可</span><span class="rel-arrow">↔</span><span class="rel-name" style="color:#FFC530;">敦敦</span></div><div class="rel-label">「守护与吃货」</div><p class="rel-desc">妙可护敦敦，敦敦用零食和吐槽回报</p></div><div class="relation-card"><div class="rel-pair"><span class="rel-name" style="color:#FF85A1;">妙可</span><span class="rel-arrow">↔</span><span class="rel-name" style="color:#74B9FF;">云雪</span></div><div class="rel-label">「看见与被看见」</div><p class="rel-desc">妙可是唯一走进云雪世界的人，云雪让妙可卸下伪装</p></div><div class="relation-card"><div class="rel-pair"><span class="rel-name" style="color:#FF9F43;">梓耀</span><span class="rel-arrow">↔</span><span class="rel-name" style="color:#FFC530;">敦敦</span></div><div class="rel-label">「最佳损友」</div><p class="rel-desc">一个负责惹事，一个负责拆台，但永远在一起</p></div><div class="relation-card"><div class="rel-pair"><span class="rel-name" style="color:#FF9F43;">梓耀</span><span class="rel-arrow">↔</span><span class="rel-name" style="color:#55EFC4;">夏老师</span></div><div class="rel-label">「最佳搭档」</div><p class="rel-desc">显眼包与摸鱼王，双向奔赴的不守规矩</p></div><div class="relation-card"><div class="rel-pair"><span class="rel-name" style="color:#00B894;">茹老师</span><span class="rel-arrow">→</span><span class="rel-name" style="opacity:0.8;">所有人</span></div><div class="rel-label">「食物链顶端」</div><p class="rel-desc">温柔但专治各种不服，连夏老师都怕她</p></div></div></div><div class="section-card"><h3>🏫 校园角落</h3><div class="scenes-banner"><img src="'+b+'" alt="青竹区第一小学全景" class="scenes-aerial-img"><div class="scenes-banner-text"><h4>青竹区第一小学 · 全景</h4><p>橙黄色局、红色跑道、开阔操场——这里的每天都是普通的，所以每天都是特别的</p></div></div><div class="scenes-grid"><div class="scene-card"><div class="scene-photo-wrap"><img src="'+u+'" alt="校门口" class="scene-photo"></div><div class="scene-info"><h4>校门口</h4><p>金字校牌伫立校门旁，早上7:20值周老师站岗，对面是小摊一条街。</p></div></div><div class="scene-card"><div class="scene-icon">🏫</div><div class="scene-info"><h4>教学楼</h4><p>五层白色教学楼，五(2)班在三楼。教室后窗能看到操场，前窗能看到梧桐道。</p></div></div><div class="scene-card"><div class="scene-icon">⚽</div><div class="scene-info"><h4>操场</h4><p>红色跑道围绿色草坪，课间操在这里，体育课在这里，夏老师摸鱼也在这里。</p></div></div><div class="scene-card"><div class="scene-icon">🍜</div><div class="scene-info"><h4>食堂</h4><p>教学楼后面平房。敦敦打饭说「多打点」，夏雨忘带饭卡在这里蹭饭。</p></div></div><div class="scene-card"><div class="scene-icon">🛒</div><div class="scene-info"><h4>校门口小摊街</h4><p>炸串（王阿姨）、烤肠（李大爷）、糖葫芦、棉花糖、文具摊。放学后的黄金地带。</p></div></div><div class="scene-card"><div class="scene-icon">🍂</div><div class="scene-info"><h4>梧桐道</h4><p>校门口主路，两边梧桐。秋天落叶满地，云雪喜欢放学后慢慢走，看落叶。</p></div></div></div></div><div class="section-card"><h3>💫 被看见的瞬间</h3><p class="section-subtitle">每一集的情感核心——那个「被看见」的小瞬间</p><div class="moments-list"><div class="moment-item"><span class="moment-ep">EP.01</span><div class="moment-body"><h4>🌧️ 烤肠与泥水</h4><p>梓耀闯了祸，但妙可看见了他手里的烤肠——知道他是怕烤肠凉了才跑那么快，而不是不在乎。</p></div></div><div class="moment-item"><span class="moment-ep">EP.02</span><div class="moment-body"><h4>⭐ 云雪的星星</h4><p>妙可看见了云雪折的星星，看见了她的沉默，看见了她没有说出口的话。</p></div></div><div class="moment-item"><span class="moment-ep">EP.03</span><div class="moment-body"><h4>🌸 春游的一天</h4><p>一天过去了。云雪看见了所有人，然后把这一天画了下来。</p></div></div></div></div><div class="section-card"><h3>📸 日常生活写真集</h3><p class="section-subtitle">光线之外的小日子——普通就是最好看的样子</p><div class="gallery-row"><div class="gallery-card"><img src="'+f+'" alt="河边醣鱼" class="gallery-img"><div class="gallery-caption"><span class="gallery-tag">🌿 周末醣鱼</span><p>好了，你负责盗多少我就盗多少。</p><span class="gallery-author">妙可 · 梓耀</span></div></div><div class="gallery-card"><img src="'+F+'" alt="雨天行走" class="gallery-img"><div class="gallery-caption"><span class="gallery-tag">🌧️ 梧桐道的雨</span><p>下雨天也没关系，反正我有一只手。</p><span class="gallery-author">梓耀 · 妙可</span></div></div></div></div><div class="section-card"><h3>🎬 妙可的生活瞬间</h3><p class="section-subtitle">去爱奇艺观看妙可的日常生活小剧场吧！——五(2)班的每一天都值得被记录</p><div class="video-link-card"><a href="https://www.iqiyi.com/creator/1547174604" target="_blank" rel="noopener noreferrer" class="video-link-btn"><span class="video-link-icon">▶</span><span class="video-link-text">前往爱奇艺观看更多《妙可的小学生活》瞬间</span><span class="video-link-arrow">→</span></a></div></div><div class="section-card philosophy-card"><h3>🎁 写给妙可的礼物</h3><p>这个番外是给妙可的礼物——让她在一个没有星光宿命的世界里，过一段完整的、平凡的、被好好爱着的童年。也是给所有人的礼物——让你想起那个放学后不急着回家的自己。</p><div class="philosophy-tags"><span>慢慢来，不着急</span><span>小事里的大情感</span><span>普通也可以发光</span></div></div>',10)])])):e("",!0),c.value==="night"?(i(),l("section",q,[...s[4]||(s[4]=[p('<div class="section-card"><h3>🌙 倾听夜的风雨</h3><div class="story-overview"><p>《倾听夜的风雨》（A Nocturne in the Rain）是《光线传奇》（Light Legend）系列的衍生特别篇作品，围绕丽丽的背景展开，是整部《光线传奇》中最沉重也最完整的人物前传。</p><p>丽丽有三个母亲：琳凯蒂亚的生母艾莲娜，在星陨之战后被白党囚禁于地牢深处，给了她守护者的血统，却无法给她一个可以回去的星空；地球的生母，在她尚不懂&quot;妈妈&quot;是什么意思的年纪将她遗弃，让她先于语言学会了被抛弃的滋味；地球的养母，以收养之名将她拐卖至异乡，让她从被遗弃的孩子变为被交易的物品。丽丽在暴风雨般的命运中独自挣扎，最终从买主家中逃出，赤脚跑过陌生的田野与公路，回到田家村口，对着已经搬走了的田野说出那句&quot;我回来了&quot;。</p><p>特别篇以&quot;倾听&quot;为名，写的是一个在三个母亲之间被传递、被丢弃、被标价的女孩，如何在从未停歇的暴风雨中，倾听着一个永远也不会响起的呼唤。</p></div></div><div class="section-card lyric-card"><h3>🎵 主题曲《倾听夜的风雨》</h3><div class="lyric-meta"><div class="lyric-meta-row"><span class="lyric-meta-label">作词</span><span class="lyric-meta-val">郭沫若，田野</span></div><div class="lyric-meta-row"><span class="lyric-meta-label">作曲</span><span class="lyric-meta-val">田野，标准音乐</span></div><div class="lyric-meta-row"><span class="lyric-meta-label">创作时间</span><span class="lyric-meta-val">2016年06月26日 下午</span></div><div class="lyric-meta-row"><span class="lyric-meta-label">修改</span><span class="lyric-meta-val">2017年05月02日</span></div></div><div class="lyric-body"><p class="lyric-stanza"> 夜是为何所惊醒<br> 敞开的窗传来淅沥<br> 打断沉沉的睡意<br> 虫儿也不在低鸣 </p><p class="lyric-stanza"> 侧着耳朵细细倾听<br> 轻脆的声音荡漾心灵<br> 我是品尝了谁的气息<br> 一阵清幽洗刷了我的心境 </p><p class="lyric-stanza"> 埋藏在心海中的记忆<br> 此刻被悄然唤醒<br> 我听见了海贝的声音<br> 在呼唤我心中的夜雨 </p></div></div>',2)])])):e("",!0),c.value==="ice"?(i(),l("section",P,[...s[5]||(s[5]=[a("div",{class:"section-card"},[a("h3",null,"❄️ 冰雪圆舞曲"),a("div",{class:"story-overview"},[a("p",null,"《冰雪圆舞曲》（Snow Globe Waltz）是《光线传奇》（Light Legend）系列的衍生爱情篇作品，以双线叙事讲述两段跨越奇幻与日常的恋情。"),a("p",null,"主线是田野与白雪——从合肥一中高二（2）班的同桌，到篮球场上那句“我会让你成为这世界上最闪耀的白雪！”；从田野变身为妙可后的含泪祝福，到多年后两人在全新的关系中找到彼此的位置。白雪送出的那个音乐盒，冰天雪地的圣诞树旋转时雪花如星，是他们的定情之物，也是他们爱情圆舞曲的序章。支线是梦雪与俊哥——妙可的姐姐与姐夫，在田野变身的风暴中默默撑起整个家庭的后方。他们的爱没有奇幻的包装."),a("p",null,"一个是风雪里攀上铁塔抢修线路的供电小伙子，一个是城市霓虹下握紧公交扶手的年轻打工妹。两条线交织出一幅完整的爱情图景：有人爱得轰轰烈烈如冰雪中的圆舞，有人爱得安静深沉如深夜里的一盏灯。奇幻可以改变身体、改变命运，却改变不了那些刻在骨子里的爱与承诺。")])],-1)])])):e("",!0)]))}};export{C as default};
